var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드, <color=#ffd34c>제프티 바이오테크</color> 본사\\n<color=#ffd34c>호라이즌</color>, 긴급기동 상태.","JPN":"シャレード、<color=#ffd34c>ジェフティ・バイオテック</color>本社\\n<color=#ffd34c>ホライズン</color>、緊急起動状態。","ENG":"<color=#ffd34c>Jehuty Biotech</color>\xA0HQ building, Charade\\n<color=#ffd34c>Horizon</color> in Emergency Mode","TWN":"查雷德，<color=#ffd34c>傑夫堤生物科技</color> 總公司\\n<color=#ffd34c>地平線</color>，緊急啟動狀態。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여동력 2.3%. 사고회로의 과부하 감지. 재기동이 필요합니다.</color>","JPN":"<color=#ff3636>残余エネルギー2.3％。思考回路の過負荷感知。再起動が必要です。</color>","ENG":"<color=#ff3636>Current remaining power is at 2.3%. Reasoning system overloaded. Reinitialization required.</color>","TWN":"<color=#ff3636>剩餘動能 2.3%。思考迴路超載，需要重新啟動。</color>"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……중요 메시지라고 끄지도 못하게 하는 주제에 징그럽게 울려대는군요.","JPN":"……重要メッセージ扱いでオフにできないとはいえ、ここまでうるさいとうんざりしますね。","ENG":"These system messages are incessantly annoying, especially since I can't turn them off.","TWN":"……一直出現訊息好吵，但因為是重要訊息也關不掉。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"추심을 종결하는 대로 펌웨어 업데이트를 서둘러야겠습니다.","JPN":"取り立てが完了次第、ファームウェアのアップデートを急いで行いましょう。","ENG":"I'd better get my firmware updated as soon as this collection job is over.","TWN":"等討完債後必須盡快更新韌體。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아하하, 뭐야? 진짜 호라이즌이네?","JPN":"アハハ！　なんだ、本当にホライズンじゃん！","ENG":"Haha, what? So it really is Horizon!","TWN":"哈哈哈～什麼嘛～真的是地平線欸！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"난 또~ 갑자기 나타났다길래 비슷하게 입은 가짜인 줄 알았잖아.","JPN":"急に現れたと聞いたから、見た目だけ似てる偽物だと思ったのに～。","ENG":"I thought an imposter dressed like you had shown up when they said you popped out of nowhere.","TWN":"你這樣突～然冒出來，我還以為只是穿著很像的冒牌貨呢～"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하마터면 또 얼굴 확인 안 하고 빵야 할 뻔 했어. 에쿵♬","JPN":"また顔の確認もしないでバキューンしちゃうところだったわ、てへっ♬","ENG":"I almost blew a hole right through you without checking your face first! Whoopsie!","TWN":"差點不分三七二十一就砰！先給你一槍了，真是的♬"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……리벳? 당신이 여기 왜 있습니까?","JPN":"……リベット？　あなたがなぜここにいるのですか？","ENG":"…Rivet? What are you doing here?","TWN":"……里維？你怎麼會在這裡？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"정말 좋은 질문이야. 나도 가끔 내가 왜 아직까지 살아 있나 고민하거든.","JPN":"めっちゃいい質問だね。アタシもたまに、なんで自分がまだ生きてるのか考えちゃうの。","ENG":"That's a great question. Sometimes I too wonder why I'm still alive.","TWN":"這個問題問得很好，我有時候也會很煩惱我怎麼還活著？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"역시 즐겁게 살아서 아닐까? 스트레스 안 받는다는 게 장수 비결이라잖아?","JPN":"やっぱり楽しく生きてるからかな？　ストレスを受けないことが長寿の秘訣らしいし！","ENG":"I guess it's all because I'm having a great time? They do say avoiding stress is key to a long and healthy life!","TWN":"是因為我活得很開心嗎？人說不是說長壽的秘訣就是沒有壓力嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"친한 척 말 걸지 말아 주시겠습니까. 굉장히 껄끄럽습니다만.","JPN":"馴れ馴れしくしないでもらえますか。とても気まずいのですが。","ENG":"I wish you'd stop feigning such personal familiarity with me. It is most unsettling.","TWN":"可以請你不要跟我裝熟嗎？我覺得很尷尬。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아잉, 왜 그래. 캄파멘토에서 같이 보냈던 스릴 넘치는 시간을 벌써 잊어 버린 거야?","JPN":"ええーそんなあ。カンパメントで一緒に過ごしたスリリングな時間をもう忘れちゃったの？","ENG":"Aw, come on. Did you already forget about the exhilarating time we spent together in Campamento?","TWN":"哎唷～幹嘛這樣～我們一起在坎帕門托度過的刺激時光，你都忘了嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기억합니다. 현지 가이드라고 속인 당신이 데몰리션 웜을 자극하는 바람에 한동안 수금을 중단해야 했죠.","JPN":"覚えています。現地ガイドだと騙ったあなたがデモリッションワームを刺激したせいで、しばらく集金を中止せざるを得なくなりました。","ENG":"I remember. I was forced to suspend my collections because you provoked a Demolition Worm after lying to me about being the local guide.","TWN":"我記得。當時你騙我你是地陪，後來還因為你刺激爆破蠕蟲，導致我必須暫時中斷討債行程。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그치? 일상에 짜릿한 활력소까지 불어 넣어 줬는데 엄청 유능한 가이드잖아?","JPN":"でしょ？　平凡な日常に刺激的なシーンを盛り込んであげられる、すごく有能なガイドだと思わない？","ENG":"Exactly! Thanks to me, that trip couldn't have been more exciting! What better guide could you ask for?","TWN":"是不是！我在平凡的日常生活當中，為你增添這麼多趣事，不是很傑出的導遊嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아잉, 그렇게 다짜고짜 쇠파이프부터 휘두르면 어떡해.","JPN":"いやーん、いきなりそんなに鉄パイプを振り回されたらびっくりしちゃうよ～。","ENG":"Aw, you could have at least given me a heads up before you started swinging away.","TWN":"哎唷～怎麼可以不先通知一聲，就用鐵管攻擊人家呢～"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"학회의 유일한 정상인을 없앨 셈이야? 너 그렇게 안 봤는데 정말 나쁜 아이구나?","JPN":"学会の唯一の常識人を潰すつもり？　アンタ、意外と悪い子だったのね！","ENG":"Are you trying to get rid of the only sane person in the Society? I didn't take you for such a meanie!","TWN":"你是打算除掉學會唯一的正常人嗎？我不知道原來你真的這麼壞喔？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"죄송합니다. 쓰레기 데이터만 배출하는 당신 주둥이를 틀어막고 싶어진 나머지 그만.","JPN":"申し訳ありません。ゴミデータばかり排出するあなたの口を塞ぎたくなったあまり、つい。","ENG":"Please excuse me. I was eager to shut that mouth of yours close so it'd stop spewing such garbage.","TWN":"抱歉，我只想堵住你那張專說廢話的嘴。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"다시 질문하겠습니다. 당신이 왜 여기 있습니까, 리벳.","JPN":"もう一度質問します。なぜあなたがここにいるのですか、リベット。","ENG":"I'll ask again. What are you doing here, Rivet?","TWN":"里維，我再問你一次，你為什麼會在這裡？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"설마 윌버에게 고용이라도 된 겁니까?","JPN":"まさかウィルバーに雇われたのですか？","ENG":"Has Wilbur hired you?","TWN":"難道是韋爾伯派你來的嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에엥~ 설마~","JPN":"ええ～まさか～！","ENG":"Aw, of course not.","TWN":"拜託～怎麼可能～"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"지금은 어디까지나 <color=#ffd34c>학회</color>에 고용된 몸이야. 여기 온 것도 고용주 때문이고.","JPN":"今はあくまでも<color=#ffd34c>学会</color>に雇われた身だよ。ここに来たのもクライアントのためだし。","ENG":"Technically, I'm hired by the <color=#ffd34c>Society</color> right now. I'm here because of the person who hired me.","TWN":"現在到處都是受雇於<color=#ffd34c>學會</color>的人好嗎？我會來這裡也是雇主叫我來的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래서 짜잔~!","JPN":"だから、ジャジャ～ン！","ENG":"So… Tada!","TWN":"所以你看～！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"어때? 침식체들이랑도 마음이 통할 수 있다는 사실, 놀랍지 않아?","JPN":"どう？　侵食体とも心が通じるの！　びっくりでしょー？","ENG":"How's that? Isn't it amazing how I can commune even with C.O.s?","TWN":"怎麼樣？有沒有嚇到？我可以和侵蝕體心靈相通欸～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"안 본 사이에 예쁜 친구 분들을 많이 사귀셨군요.","JPN":"見ない間に素敵なお友達がたくさんできたのですね。","ENG":"I see you've made many lovely friends since the last time we met.","TWN":"這段時間沒見，你交了不少好看的朋友呢。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오우, 피부가 엄청 매끈하지?","JPN":"でしょでしょーお肌すべすべでいいでしょー？","ENG":"They do have impeccable skin, don't they?","TWN":"哇喔～皮膚超滑的～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"비결이 뭐냐고 물어 봤더니 편식 안 하고 양껏 먹기래.","JPN":"美肌の秘訣を聞いたら、偏食せずにたくさん食べることらしいよ。","ENG":"I asked them what their secret was, and apparently it's to eat their fill without getting picky.","TWN":"問他秘訣是什麼，他說不能挑食，每餐都要盡量吃飽。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래서 여기 있던 <color=#ffd34c>지식</color>들만으로는 간에 기별도 안 온다지 뭐야.","JPN":"で、ここにある<color=#ffd34c>知識</color>だけでは全然足りないんだって。","ENG":"So the <color=#ffd34c>knowledge</color> here won't even come close to satisfying their hunger.","TWN":"這裡的<color=#ffd34c>知識</color>根本就不夠我塞牙縫嘛～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"네가 좀 도와 줄래, 호라이즌?","JPN":"だからホライズン、アンタちょっと手伝ってくれない？","ENG":"Would you like to help them out, Horizon?","TWN":"你可以幫我嗎，地平線？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저를 먹었다간 소화 불량에 걸리겠죠. 거절하겠습니다.","JPN":"私を食べたら消化不良になるだけです。お断りします。","ENG":"Eating me would only lead to indigestion. I must decline.","TWN":"吃我的話應該會消化不良吧，我拒絕。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응? 그거야 확인해 보지 않으면 어떻게 될지 아무도 모르잖아?","JPN":"ええーそれは確かめてみないとわからないよ？","ENG":"Hm? How would you know until we've tried it?","TWN":"可是，不吃吃看怎麼知道呢？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"자, 자. 네가 그 윌 뭐시기 씨를 잡으려고 한다는 소식을 듣고 잽싸게 달려왔다구.","JPN":"アタシはね、アンタがそのウィルなんちゃらさんを捕まえようとしてるって聞いてここまで飛んできたのよ。","ENG":"Come on, now. I ran over here as fast as I could when I heard you're on your way to whack that Wil-whatever-his-name-is.","TWN":"好嘛好嘛～我可是聽到消息說你要找那個韋什麼的，就拼命跑過來欸！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"가짜면 때려잡고 할 일이나 하다 가려 했는데, 놀다가 레지나한테 혼나게 생겼잖아! 책임져!","JPN":"偽物ならさっさとぶったたいて適当に仕事して帰ろうとしたけど、本物のアンタに何もしないで帰ったらレジーナに怒られちゃうよ！　だから責任取って！","ENG":"I was gonna just do my job and be done with it if you were an imposter, but now I'm gonna get in trouble with Regina for goofing off! This is on you!","TWN":"本來想說如果是冒牌貨，就隨便射兩槍，然後辦完事情就回去的。結果現在蕾佳娜不開心啦！你要負責～！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러니까 원없이 쏘게 해 줄 거지? 필사적으로 뿌슝빠슝♬ 하게 해 줄 거지? 응? 호라이즌?","JPN":"だからバキュンバキュン♬させて？　バーンって撃ってドーンとさせてよ。ね？　ホライズン？","ENG":"So you'll let me shoot all I want, right? You'll let me get all trigger happy, right? Hm? Horizon?","TWN":"所以你應該會很樂意讓我射一槍吧？你會讓我砰～砰～♬一槍斃命吧？會嗎？地平線？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리벳. 저는 당신처럼 스릴에 중독된 미치광이와 상종하지 않습니다.","JPN":"リベット、私はあなたのようなスリル狂はとても苦手なので、相手にしたくありません。","ENG":"Rivet. I don't deal with lunatics drunk on the thrill of danger like you.","TWN":"里維，我和你這種對刺激上癮的瘋子合不來。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"승강기를 사용해야 하니 용무가 끝났으면 어서 이 건물에서 꺼져 주시죠.","JPN":"エレベーターを使いたいので、用事が終わったなら早くこの建物から出て行ってください。","ENG":"I must use the elevator. Please remove yourself from this building if you're done with your business.","TWN":"我要去搭電梯，沒事的話，就請你快滾出這棟建築物。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"앗. 그건 안 돼, 호라이즌.","JPN":"あっ、それはダメなのホライズン。","ENG":"Oh! I'm afraid I can't do that, Horizon.","TWN":"哎呀～那可不行喔，地平線。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"난 지금 학회의 감찰관으로서 여기 온 거거든.","JPN":"私は今、学会の監察官としてここに来ているワケ。","ENG":"I'm here as the Society's inspector, you see?","TWN":"我可是以學會監察委員的身份來的。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"감찰관?","JPN":"監察官？","ENG":"Inspector?","TWN":"監察委員？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"필요한 지식은 챙기고, 남들이 알면 골치 아파지는 지식은 없애고.","JPN":"必要な知識は手に入れて、他人に知られたら困る知識は消す。","ENG":"I'm here to retrieve any useful knowledge, and get rid of anything that could be uncomfortable if anyone else was to find out.","TWN":"像是預備需要的知識，或是除掉不能讓其他人知道的知識。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그런데 이 위는 분리수거가 아직 덜 끝났단 말이야.","JPN":"でも、この上のエリアの分別はまだ終わってないの。","ENG":"The thing is, I haven't finished cleaning up, up there.","TWN":"不過現在主要是垃圾回收還沒處理完。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"핑계가 장황하군요, 리벳.","JPN":"言い訳が長いですね、リベット。","ENG":"You present a rather elaborate excuse, Rivet.","TWN":"里維，你的解說好冗長。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이란 휴먼은 거짓말쟁이입니다. 원하는 건 결국 방아쇠를 당길 구실이지 않습니까.","JPN":"あなたというヒューマンは一貫して噓つきです。結局その引き金を引く口実を探しているだけではないですか。","ENG":"But I know you for the liar that you are, human. All you really want is an excuse to pull that trigger.","TWN":"你這種人類是騙子，說這麼多，都只是你想扣下板機的藉口而已。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"응! 맞아! 요즘 총을 너~무 안 쐈더니 거울에 비친 내 이마가 과녁판으로 보이는 거 있지?","JPN":"うん！　そうだよ！　最近銃を撃つ機会がなくて、鏡に映った自分のおでこが的に見えるぐらいなの！","ENG":"Yup! You got me! I started seeing a bullseye on my own forehead because I haven't shot a single bullet in ages!","TWN":"嗯！沒錯！最近太～少用槍，照鏡子的時候，還以為我的額頭是標靶呢！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 이전과 같은 대답을 드려야겠군요.","JPN":"でしたら以前と同じ返事をさせていただきます。","ENG":"Then I have the same answer for you as last time.","TWN":"那我必須給你相同的回答。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"더 늦기 전에 정신과 상담을 받으시죠.","JPN":"手遅れになる前に精神科で相談してみるのはどうですか。","ENG":"Go get some therapy before it's too late.","TWN":"趕快找時間去做心理諮商。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 이런데도 계속 매정하게 굴래?","JPN":"いやーん、ここまで話したのにそんな冷たいこと言わないでよ。","ENG":"Aw, come on. Do you really need to be so heartless?","TWN":"哎呀～怎麼還是這麼冷淡呢？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"나 그럼 그 레이첼이란 애 이마 과녁판으로 써도 돼? 내 이마는 소중하잖아?","JPN":"じゃあ、あのレイチェルって子のおでこを的にしてもいい？　アタシのおでこは大切だから！","ENG":"Then can I use that Rachel girl's forehead as the bullseye instead? I'd rather keep my own forehead, you see.","TWN":"那還是我可以把那個叫瑞秋的額頭當作標靶？畢竟我的額頭很珍貴的嘛～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"로봇이면서 되게 센티멘탈하다니까. 너 질풍노도의 시기인 거 엄마가 아시니?","JPN":"んもーロボットのくせにすごいセンチメンタルだね。アンタが今思春期真っ只中ってお母さんは知ってるの？","ENG":"You're awfully emotional for a robot. Does your mommy know how naughty you've been?","TWN":"明明是個機器人，卻滿意氣用事的嘛～媽咪知道你現在是叛逆期嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"도발이 성공했다고 지금 자축이나 해 두시죠, 휴먼.","JPN":"挑発に成功したと喜べるのは今のうちだけです、ヒューマン。","ENG":"You should pat yourself on the back for successfully provoking me when you still can, human.","TWN":"你就趁現在慶祝激將法成功吧，人類。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"병상에 누워 있는 상태로는 힘들 겁니다.","JPN":"病床に横たわった状態では厳しいでしょう。","ENG":"Because you'll find yourself rather immobilized when you're in a hospital bed.","TWN":"因為等你躺在醫院病床上時，要慶祝可能會有困難。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"꺄하하하! 만세! 해냈다!","JPN":"キャハハハ！　わーい、やったー！","ENG":"Kya hah hah hah! Yay! I did it!","TWN":"哇哈哈哈！萬歲！成功！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그럼 어디, 오랜만에 신나게 터트려 볼까?","JPN":"さてさてさて、久しぶりに暴れてみよっかな！","ENG":"Time for some awesome fireworks, then!","TWN":"那要久違的來一場嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"}]`);export{e as default};